        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        double distance = sqrt( pow((double)(xe-(int)roundDouble(IszY/2.0)),2) + pow((double)(ye-(int)roundDouble(IszX/2.0)),2) );
        printf("%lf\n", distance);

        CDF[0] = weights[0];
        for(x = 1; Nparticles > x; x++){
            CDF[x] = weights[x] + CDF[x-1];
        }
        long long cum_sum = get_time();
        printf("TIME TO CALC CUM SUM TOOK: %f\n", elapsed_time(move_time, cum_sum));
        double u1 = (1/((double)(Nparticles)))*randu(seed, 0);
        for(x = 0; Nparticles > x; x++){
            u[x] = u1 + x/((double)(Nparticles));
        }
        long long u_time = get_time();
        printf("TIME TO CALC U TOOK: %f\n", elapsed_time(cum_sum, u_time));
        long long start_copy = get_time();

        clEnqueueWriteBuffer(cmd_queue, arrayX_GPU, 1, 0, sizeof(double)*Nparticles, arrayX, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, arrayY_GPU, 1, 0, sizeof(double)*Nparticles, arrayY, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, xj_GPU, 1, 0, sizeof(double)*Nparticles, xj, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, yj_GPU, 1, 0, sizeof(double)*Nparticles, yj, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, CDF_GPU, 1, 0, sizeof(double)*Nparticles, CDF, 0, 0, NULL);
        clEnqueueWriteBuffer(cmd_queue, u_GPU, 1, 0, sizeof(double)*Nparticles, u, 0, 0, NULL);
        clFinish(cmd_queue);
        long long end_copy = get_time();

        int num_blocks = ceil((double) Nparticles/(double) threads_per_block);
        size_t local_work[3] = {threads_per_block, 1, 1};
        size_t global_work[3] = {num_blocks*threads_per_block, 1, 1};

        clSetKernelArg(kernel_obj, 0, sizeof(cl_mem), &arrayX_GPU);
        clSetKernelArg(kernel_obj, 1, sizeof(cl_mem), &arrayY_GPU);
        clSetKernelArg(kernel_obj, 2, sizeof(cl_mem), &CDF_GPU);
        clSetKernelArg(kernel_obj, 3, sizeof(cl_mem), &u_GPU);
        clSetKernelArg(kernel_obj, 4, sizeof(cl_mem), &xj_GPU);
        clSetKernelArg(kernel_obj, 5, sizeof(cl_mem), &yj_GPU);
        clSetKernelArg(kernel_obj, 6, sizeof(cl_int), &Nparticles);

        err = clEnqueueNDRangeKernel(cmd_queue, kernel_obj, 1, NULL, global_work, local_work, 0, 0, NULL);
        check_error(err);
        clFinish(cmd_queue);
        long long start_copy_back = get_time();

        clEnqueueReadBuffer(cmd_queue, yj_GPU, 1, 0, sizeof(double)*Nparticles, yj, 0, 0, NULL);
        clEnqueueReadBuffer(cmd_queue, xj_GPU, 1, 0, sizeof(double)*Nparticles, xj, 0, 0, NULL);
        clFinish(cmd_queue);
        long long end_copy_back = get_time();
        printf("SENDING TO GPU TOOK: %lf\n", elapsed_time(start_copy, end_copy));
        printf("CUDA EXEC TOOK: %lf\n", elapsed_time(end_copy, start_copy_back));
        printf("SENDING BACK FROM GPU TOOK: %lf\n", elapsed_time(start_copy_back, end_copy_back));
        long long xyj_time = get_time();
        printf("TIME TO CALC NEW ARRAY X AND Y TOOK: %f\n", elapsed_time(u_time, xyj_time));

        for(x = 0; Nparticles > x; x++){
            arrayX[x] = xj[x];
            arrayY[x] = yj[x];
            weights[x] = 1/((double)(Nparticles));
        }
        long long reset = get_time();
        printf("TIME TO RESET WEIGHTS TOOK: %f\n", elapsed_time(xyj_time, reset));
    }

    clReleaseMemObject(u_GPU);
    clReleaseMemObject(CDF_GPU);
    clReleaseMemObject(yj_GPU);
    clReleaseMemObject(xj_GPU);
    clReleaseMemObject(arrayY_GPU);
    clReleaseMemObject(arrayX_GPU);
    clReleaseKernel(kernel_obj);
    clReleaseProgram(prog);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(arrayX);
    free(arrayY);
    free(xj);
    free(yj);
    free(CDF);
    free(u);
}

int main(int argc, char * argv[]){
    char* usage = "naive.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles>";

    if(9 != argc) {
        printf("%s\n", usage);
        return 0;
    }

    if( strcmp( argv[1], "-x" ) ||  strcmp( argv[3], "-y" ) || strcmp( argv[5], "-z" ) || strcmp( argv[7], "-np" ) ) {
        printf( "%s\n",usage );
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if( sscanf( argv[2], "%d", &IszX ) == EOF ) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if( 0 >= IszX ) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if( sscanf( argv[4], "%d", &IszY ) == EOF ) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if( 0 >= IszY ) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if( sscanf( argv[6], "%d", &Nfr ) == EOF ) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if( 0 >= Nfr ) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if( sscanf( argv[8], "%d", &Nparticles ) == EOF ) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if( 0 >= Nparticles ) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    for (int i = 9; i < argc; ++i) {
        switch (argv[i][1]) {
        case 'p':	
            if (++i < argc)
                sscanf(argv[i], "%d", &platform_id_inuse);
            break;
        case 'd':	 
            if (++i < argc)
                sscanf(argv[i], "%d", &device_id_inuse);
            break;
        default:
            ;
        }
    }

    int * seed = (int *)malloc(sizeof(int)*Nparticles);
    int i;
    for(i = 0; Nparticles > i; i++)
        seed[i] = time(0)*i;

    int * I = (int *)malloc(sizeof(int)*IszX*IszY*Nfr);
    long long start = get_time();

    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time(start, endVideoSequence));

    if (initialize()) return -1;

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);

    shutdown();

    long long endParticleFilter = get_time();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}
